vector<string> removeInvalidParentheses(string s) {
    vector<string> result;
    int openBrackets = 0;
    for (char c : s) {
        if (c == '(') {
            openBrackets++;
        } else if (c == ')') {
            openBrackets--;
            if (openBrackets < 0) {
                continue;
            }
        }
        result.push_back(s.substr(result.size(), s.length()));
    }
    return result;
}

